    long[] left_start = new long[n];
    left_start[0] = 0;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left_start[i] = left_start[i - 1];
        } else {
            left_start[i] = i;
        }
    }

    long[] right_end = new long[n];
    right_end[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            right_end[i] = right_end[i + 1];
        } else {
            right_end[i] = i;
        }
    }

    long[] right_incr_end = new long[n];
    right_incr_end[n - 1] = n - 1;
    for (int i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right_incr_end[i] = right_incr_end[i + 1];
        } else {
            right_incr_end[i] = i;
        }
    }

    long[] prefix_sum = new long[n + 1];
    prefix_sum[0] = 0;
    for (int i = 0; i < n; i++) {
        prefix_sum[i + 1] = prefix_sum[i] + nums[i];
    }

    long max_sum = Long.MIN_VALUE;
    for (int p = 0; p < n; p++) {
        long q = right_end[p];
        if (q > p) {
            if (right_incr_end[q] > q) {
                long l = left_start[p];
                long r = right_incr_end[q];
                long current_sum = prefix_sum[r + 1] - prefix_sum[l];
                if (current_sum > max_sum) {
                    max_sum = current_sum;
                }
            }
        }
    }

    return max_sum;
}
